from itertools import permutations

class Solution(object):
    def minimumString(self, a, b, c):
        def overlap(x, y):
            # Find max overlap where suffix of x = prefix of y
            for i in range(min(len(x), len(y)), 0, -1):
                if x[-i:] == y[:i]:
                    return i
            return 0

        def merge(x, y):
            # If y is a substring of x, no extra characters needed
            if y in x:
                return x
            ov = overlap(x, y)
            return x + y[ov:]

        best = None
        for perm in permutations([a, b, c]):
            candidate = merge(merge(perm[0], perm[1]), perm[2])
            if best is None or len(candidate) < len(best) or \
               (len(candidate) == len(best) and candidate < best):
                best = candidate
        return best
